#pragma once\\\\\n#include <cstdint>\\\\\n// Stable baseline implementation matching interface; no intrinsics nor assumptions on output order beyond spec\\\\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\n    // Process each output element with loop unrolling of 16 for predictable access\\n    for (size_t i = 0; i < M; ++i) {\\\\n        for (size_t j = 0; j < K; j += 16) {\\\\n            float accum[16]; // temporary accumulator\\\n            for (size_t k = 0; k < K; ++k) {\\\\n                // Decode sign from B[k][j] at packed index\\n                uint32_t bval = B[k * (K/32) + j / 32];\\\\n                int32_t b_bit = (bval >> (int(j) % 32)) & 1u; // extract (j % 32)-th bit\\\n                float sign = b_bit ? 1.0f : -1.0f;\\\n                accum[k % 16] += A[i*K + k] * sign;\\\n            }\\\\n            // Store 16 results in one shot\\n            for (size_t ks = 0; ks < 16; ++ks) {\\n                if (j + ks < K) C[i*K + j + ks] = accum[ks];\n            }\\n        }\n    }\\n}